"""
Parameterized generator for GH743_hyper_4001.

Source PR:    https://github.com/hyperium/hyper/pull/4001
Source Issue: https://github.com/hyperium/hyper/issues/3984

Seed varies: renames 'addr' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH743_hyper_4001'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH743_hyper_4001'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('addr', 'addr' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH743_hyper_4001',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'hyperium/hyper',
                "pr_number": 4001,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/hyperium/hyper/pull/4001",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'examples/params.rs': '// #![deny(warnings)]  // FIXME: https://github.com/rust-lang/rust/issues/62411\n#![warn(rust_2018_idioms)]\n\nuse bytes::Bytes;\nuse http_body_util::{combinators::BoxBody, BodyExt, Empty, Full};\nuse hyper::server::conn::http1;\nuse hyper::service::service_fn;\nuse hyper::{Method, Request, Response, StatusCode};\nuse tokio::net::TcpListener;\n\nuse std::collections::HashMap;\nuse std::convert::Infallible;\nuse std::net::SocketAddr;\n\n#[path = "../benches/support/mod.rs"]\nmod support;\nuse support::TokioIo;\n\nstatic INDEX: &[u8] = b"<html><body><form action=\\"post\\" method=\\"post\\">Name: <input type=\\"text\\" name=\\"name\\"><br>Number: <input type=\\"text\\" name=\\"number\\"><br><input type=\\"submit\\"></body></html>";\nstatic MISSING: &[u8] = b"Missing field";\nstatic NOTNUMERIC: &[u8] = b"Number field is not numeric";\n\n// Using service_fn, we can turn this function into a `Service`.\nasync fn param_example(\n    req: Request<hyper::body::Incoming>,\n) -> Result<Response<BoxBody<Bytes, Infallible>>, hyper::Error> {\n    match (req.method(), req.uri().path()) {\n        (&Method::GET, "/") | (&Method::GET, "/post") => Ok(Response::new(full(INDEX))),\n        (&Method::POST, "/post") => {\n            // Concatenate the body...\n            let b = req.collect().await?.to_bytes();\n            // Parse the request body. form_urlencoded::parse\n            // always succeeds, but in general parsing may\n            // fail (for example, an invalid post of json), so\n            // returning early with BadRequest may be\n            // necessary.\n            //\n            // Warning: this is a simplified use case. In\n            // principle names can appear multiple times in a\n            // form, and the values should be rolled up into a\n            // HashMap<String, Vec<String>>. However in this\n            // example the simpler approach is sufficient.\n            let params = form_urlencoded::parse(b.as_ref())\n                .into_owned()\n                .collect::<HashMap<String, String>>();\n\n            // Validate the request parameters, returning\n            // early if an invalid input is detected.\n            let name = if let Some(n) = params.get("name") {\n                n\n            } else {\n                return Ok(Response::builder()\n                    .status(StatusCode::UNPROCESSABLE_ENTITY)\n                    .body(full(MISSING))\n                    .unwrap());\n            };\n            let number = if let Some(n) = params.get("number") {\n                if let Ok(v) = n.parse::<f64>() {\n                    v\n                } else {\n                    return Ok(Response::builder()\n                        .status(StatusCode::UNPROCESSABLE_ENTITY)\n                        .body(full(NOTNUMERIC))\n                        .unwrap());\n                }\n            } else {\n                return Ok(Response::builder()\n                    .status(StatusCode::UNPROCESSABLE_ENTITY)\n                    .body(full(MISSING))\n                    .unwrap());\n            };\n\n            // Render the response. This will often involve\n            // calls to a database or web service, which will\n            // require creating a new stream for the response\n            // body. Since those may fail, other error\n            // responses such as InternalServiceError may be\n            // needed here, too.\n            let body = format!("Hello {}, your number is {}", name, number);\n            Ok(Response::new(full(body)))\n        }\n        (&Method::GET, "/get") => {\n            let query = if let Some(q) = req.uri().query() {\n                q\n            } else {\n                return Ok(Response::builder()\n                    .status(StatusCode::UNPROCESSABLE_ENTITY)\n                    .body(full(MISSING))\n                    .unwrap());\n            };\n            let params = form_urlencoded::parse(query.as_bytes())\n                .into_owned()\n                .collect::<HashMap<String, String>>();\n            let page = if let Some(p) = params.get("page") {\n                p\n            } else {\n                return Ok(Response::builder()\n                    .status(StatusCode::UNPROCESSABLE_ENTITY)\n                    .body(full(MISSING))\n                    .unwrap());\n            };\n            let body = format!("You requested {}", page);\n            Ok(Response::new(full(body)))\n        }\n        _ => Ok(Response::builder()\n            .status(StatusCode::NOT_FOUND)\n            .body(empty())\n            .unwrap()),\n    }\n}\n\nfn empty() -> BoxBody<Bytes, Infallible> {\n    Empty::<Bytes>::new().boxed()\n}\n\nfn full<T: Into<Bytes>>(chunk: T) -> BoxBody<Bytes, Infallible> {\n    Full::new(chunk.into()).boxed()\n}\n\n#[tokio::main]\nasync fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {\n    pretty_env_logger::init();\n\n    let addr: SocketAddr = ([127, 0, 0, 1], 1337).into();\n\n    let listener = TcpListener::bind(addr).await?;\n    println!("Listening on http://{}", addr);\n    loop {\n        let (stream, _) = listener.accept().await?;\n        let io = TokioIo::new(stream);\n\n        tokio::task::spawn(async move {\n            if let Err(err) = http1::Builder::new()\n                .serve_connection(io, service_fn(param_example))\n                .await\n            {\n                println!("Error serving connection: {:?}", err);\n            }\n        });\n    }\n}\n',
            'examples/send_file.rs': '#![deny(warnings)]\n\nuse std::net::SocketAddr;\n\nuse bytes::Bytes;\nuse futures_util::TryStreamExt;\nuse http_body_util::{combinators::BoxBody, BodyExt, Full, StreamBody};\nuse hyper::body::Frame;\nuse hyper::server::conn::http1;\nuse hyper::service::service_fn;\nuse hyper::{Method, Request, Response, Result, StatusCode};\nuse tokio::{fs::File, net::TcpListener};\nuse tokio_util::io::ReaderStream;\n\n#[path = "../benches/support/mod.rs"]\nmod support;\nuse support::TokioIo;\n\nstatic INDEX: &str = "examples/send_file_index.html";\nstatic NOTFOUND: &[u8] = b"Not Found";\n\n#[tokio::main]\nasync fn main() -> std::result::Result<(), Box<dyn std::error::Error>> {\n    pretty_env_logger::init();\n\n    let addr: SocketAddr = "127.0.0.1:1337".parse().unwrap();\n\n    let listener = TcpListener::bind(addr).await?;\n    println!("Listening on http://{}", addr);\n\n    loop {\n        let (stream, _) = listener.accept().await?;\n        let io = TokioIo::new(stream);\n\n        tokio::task::spawn(async move {\n            if let Err(err) = http1::Builder::new()\n                .serve_connection(io, service_fn(response_examples))\n                .await\n            {\n                println!("Failed to serve connection: {:?}", err);\n            }\n        });\n    }\n}\n\nasync fn response_examples(\n    req: Request<hyper::body::Incoming>,\n) -> Result<Response<BoxBody<Bytes, std::io::Error>>> {\n    match (req.method(), req.uri().path()) {\n        (&Method::GET, "/") | (&Method::GET, "/index.html") => simple_file_send(INDEX).await,\n        (&Method::GET, "/no_file.html") => {\n            // Test what happens when file cannot be found\n            simple_file_send("this_file_should_not_exist.html").await\n        }\n        _ => Ok(not_found()),\n    }\n}\n\n/// HTTP status code 404\nfn not_found() -> Response<BoxBody<Bytes, std::io::Error>> {\n    Response::builder()\n        .status(StatusCode::NOT_FOUND)\n        .body(Full::new(NOTFOUND.into()).map_err(|e| match e {}).boxed())\n        .unwrap()\n}\n\nasync fn simple_file_send(filename: &str) -> Result<Response<BoxBody<Bytes, std::io::Error>>> {\n    // Open file for reading\n    let file = File::open(filename).await;\n    if file.is_err() {\n        eprintln!("ERROR: Unable to open file.");\n        return Ok(not_found());\n    }\n\n    let file: File = file.unwrap();\n\n    // Wrap to a tokio_util::io::ReaderStream\n    let reader_stream = ReaderStream::new(file);\n\n    // Convert to http_body_util::BoxBody\n    let stream_body = StreamBody::new(reader_stream.map_ok(Frame::data));\n    let boxed_body = stream_body.boxed();\n\n    // Send response\n    let response = Response::builder()\n        .status(StatusCode::OK)\n        .body(boxed_body)\n        .unwrap();\n\n    Ok(response)\n}\n',
            'examples/service_struct_impl.rs': 'use bytes::Bytes;\nuse http_body_util::Full;\nuse hyper::server::conn::http1;\nuse hyper::service::Service;\nuse hyper::{body::Incoming as IncomingBody, Request, Response};\nuse tokio::net::TcpListener;\n\nuse std::future::Future;\nuse std::net::SocketAddr;\nuse std::pin::Pin;\nuse std::sync::{Arc, Mutex};\n\n#[path = "../benches/support/mod.rs"]\nmod support;\nuse support::TokioIo;\n\ntype Counter = i32;\n\n#[tokio::main]\nasync fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {\n    let addr: SocketAddr = ([127, 0, 0, 1], 3000).into();\n\n    let listener = TcpListener::bind(addr).await?;\n    println!("Listening on http://{}", addr);\n\n    let svc = Svc {\n        counter: Arc::new(Mutex::new(0)),\n    };\n\n    loop {\n        let (stream, _) = listener.accept().await?;\n        let io = TokioIo::new(stream);\n        let svc_clone = svc.clone();\n        tokio::task::spawn(async move {\n            if let Err(err) = http1::Builder::new().serve_connection(io, svc_clone).await {\n                println!("Failed to serve connection: {:?}", err);\n            }\n        });\n    }\n}\n\n#[derive(Debug, Clone)]\nstruct Svc {\n    counter: Arc<Mutex<Counter>>,\n}\n\nimpl Service<Request<IncomingBody>> for Svc {\n    type Response = Response<Full<Bytes>>;\n    type Error = hyper::Error;\n    type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>> + Send>>;\n\n    fn call(&self, req: Request<IncomingBody>) -> Self::Future {\n        fn mk_response(s: String) -> Result<Response<Full<Bytes>>, hyper::Error> {\n            Ok(Response::builder().body(Full::new(Bytes::from(s))).unwrap())\n        }\n\n        if req.uri().path() != "/favicon.ico" {\n            *self.counter.lock().expect("lock poisoned") += 1;\n        }\n\n        let res = match req.uri().path() {\n            "/" => mk_response(format!("home! counter = {:?}", self.counter)),\n            "/posts" => mk_response(format!("posts, of course! counter = {:?}", self.counter)),\n            "/authors" => mk_response(format!(\n                "authors extraordinare! counter = {:?}",\n                self.counter\n            )),\n            _ => mk_response("oh no! not found".into()),\n        };\n\n        Box::pin(async { res })\n    }\n}\n',
            'examples/upgrades.rs': '#![deny(warnings)]\n\n// Note: `hyper::upgrade` docs link to this upgrade.\nuse std::net::SocketAddr;\nuse std::str;\n\nuse tokio::io::{AsyncReadExt, AsyncWriteExt};\nuse tokio::net::{TcpListener, TcpStream};\nuse tokio::sync::watch;\n\nuse bytes::Bytes;\nuse http_body_util::Empty;\nuse hyper::header::{HeaderValue, UPGRADE};\nuse hyper::server::conn::http1;\nuse hyper::service::service_fn;\nuse hyper::upgrade::Upgraded;\nuse hyper::{Request, Response, StatusCode};\n\n#[path = "../benches/support/mod.rs"]\nmod support;\nuse support::TokioIo;\n\n// A simple type alias so as to DRY.\ntype Result<T> = std::result::Result<T, Box<dyn std::error::Error + Send + Sync>>;\n\n/// Handle server-side I/O after HTTP upgraded.\nasync fn server_upgraded_io(upgraded: Upgraded) -> Result<()> {\n    let mut upgraded = TokioIo::new(upgraded);\n    // we have an upgraded connection that we can read and\n    // write on directly.\n    //\n    // since we completely control this example, we know exactly\n    // how many bytes the client will write, so just read exact...\n    let mut vec = vec![0; 7];\n    upgraded.read_exact(&mut vec).await?;\n    println!("server[foobar] recv: {:?}", str::from_utf8(&vec));\n\n    // and now write back the server \'foobar\' protocol\'s\n    // response...\n    upgraded.write_all(b"bar=foo").await?;\n    println!("server[foobar] sent");\n    Ok(())\n}\n\n/// Our server HTTP handler to initiate HTTP upgrades.\nasync fn server_upgrade(mut req: Request<hyper::body::Incoming>) -> Result<Response<Empty<Bytes>>> {\n    let mut res = Response::new(Empty::new());\n\n    // Send a 400 to any request that doesn\'t have\n    // an `Upgrade` header.\n    if !req.headers().contains_key(UPGRADE) {\n        *res.status_mut() = StatusCode::BAD_REQUEST;\n        return Ok(res);\n    }\n\n    // Setup a future that will eventually receive the upgraded\n    // connection and talk a new protocol, and spawn the future\n    // into the runtime.\n    //\n    // Note: This can\'t possibly be fulfilled until the 101 response\n    // is returned below, so it\'s better to spawn this future instead\n    // waiting for it to complete to then return a response.\n    tokio::task::spawn(async move {\n        match hyper::upgrade::on(&mut req).await {\n            Ok(upgraded) => {\n                if let Err(e) = server_upgraded_io(upgraded).await {\n                    eprintln!("server foobar io error: {}", e)\n                };\n            }\n            Err(e) => eprintln!("upgrade error: {}", e),\n        }\n    });\n\n    // Now return a 101 Response saying we agree to the upgrade to some\n    // made-up \'foobar\' protocol.\n    *res.status_mut() = StatusCode::SWITCHING_PROTOCOLS;\n    res.headers_mut()\n        .insert(UPGRADE, HeaderValue::from_static("foobar"));\n    Ok(res)\n}\n\n/// Handle client-side I/O after HTTP upgraded.\nasync fn client_upgraded_io(upgraded: Upgraded) -> Result<()> {\n    let mut upgraded = TokioIo::new(upgraded);\n    // We\'ve gotten an upgraded connection that we can read\n    // and write directly on. Let\'s start out \'foobar\' protocol.\n    upgraded.write_all(b"foo=bar").await?;\n    println!("client[foobar] sent");\n\n    let mut vec = Vec::new();\n    upgraded.read_to_end(&mut vec).await?;\n    println!("client[foobar] recv: {:?}", str::from_utf8(&vec));\n\n    Ok(())\n}\n\n/// Our client HTTP handler to initiate HTTP upgrades.\nasync fn client_upgrade_request(addr: SocketAddr) -> Result<()> {\n    let req = Request::builder()\n        .uri(format!("http://{}/", addr))\n        .header(UPGRADE, "foobar")\n        .body(Empty::<Bytes>::new())\n        .unwrap();\n\n    let stream = TcpStream::connect(addr).await?;\n    let io = TokioIo::new(stream);\n    let (mut sender, conn) = hyper::client::conn::http1::handshake(io).await?;\n\n    tokio::task::spawn(async move {\n        // Don\'t forget to enable upgrades on the connection.\n        if let Err(err) = conn.with_upgrades().await {\n            println!("Connection failed: {:?}", err);\n        }\n    });\n\n    let res = sender.send_request(req).await?;\n\n    if res.status() != StatusCode::SWITCHING_PROTOCOLS {\n        panic!("Our server didn\'t upgrade: {}", res.status());\n    }\n\n    match hyper::upgrade::on(res).await {\n        Ok(upgraded) => {\n            if let Err(e) = client_upgraded_io(upgraded).await {\n                eprintln!("client foobar io error: {}", e)\n            };\n        }\n        Err(e) => eprintln!("upgrade error: {}", e),\n    }\n\n    Ok(())\n}\n\n#[tokio::main]\nasync fn main() {\n    // For this example, we just make a server and our own client to talk to\n    // it, so the exact port isn\'t important. Instead, let the OS give us an\n    // unused port.\n    let addr: SocketAddr = ([127, 0, 0, 1], 0).into();\n\n    let listener = TcpListener::bind(addr).await.expect("failed to bind");\n\n    // We need the assigned address for the client to send it messages.\n    let addr = listener.local_addr().unwrap();\n\n    // For this example, a oneshot is used to signal that after 1 request,\n    // the server should be shutdown.\n    let (tx, mut rx) = watch::channel(false);\n\n    // Spawn server on the default executor,\n    // which is usually a thread-pool from tokio default runtime.\n    tokio::task::spawn(async move {\n        loop {\n            tokio::select! {\n                res = listener.accept() => {\n                    let (stream, _) = res.expect("Failed to accept");\n                    let io = TokioIo::new(stream);\n\n                    let mut rx = rx.clone();\n                    tokio::task::spawn(async move {\n                        let conn = http1::Builder::new().serve_connection(io, service_fn(server_upgrade));\n\n                        // Don\'t forget to enable upgrades on the connection.\n                        let mut conn = conn.with_upgrades();\n\n                        let mut conn = Pin::new(&mut conn);\n\n                        tokio::select! {\n                            res = &mut conn => {\n                                if let Err(err) = res {\n                                    println!("Error serving connection: {:?}", err);\n                                }\n                            }\n                            // Continue polling the connection after enabling graceful shutdown.\n                            _ = rx.changed() => {\n                                conn.graceful_shutdown();\n                            }\n                        }\n                    });\n                }\n                _ = rx.changed() => {\n                    break;\n                }\n            }\n        }\n    });\n\n    // Client requests a HTTP connection upgrade.\n    let request = client_upgrade_request(addr);\n    if let Err(e) = request.await {\n        eprintln!("client error: {}", e);\n    }\n\n    // Complete the oneshot so that the server stops\n    // listening and the process can close down.\n    let _ = tx.send(true);\n}\n',
            'examples/web_api.rs': '#![deny(warnings)]\n\nuse std::net::SocketAddr;\n\nuse bytes::{Buf, Bytes};\nuse http_body_util::{BodyExt, Full};\nuse hyper::server::conn::http1;\nuse hyper::service::service_fn;\nuse hyper::{body::Incoming as IncomingBody, header, Method, Request, Response, StatusCode};\nuse tokio::net::{TcpListener, TcpStream};\n\n#[path = "../benches/support/mod.rs"]\nmod support;\nuse support::TokioIo;\n\ntype GenericError = Box<dyn std::error::Error + Send + Sync>;\ntype Result<T> = std::result::Result<T, GenericError>;\ntype BoxBody = http_body_util::combinators::BoxBody<Bytes, hyper::Error>;\n\nstatic INDEX: &[u8] = b"<a href=\\"test.html\\">test.html</a>";\nstatic INTERNAL_SERVER_ERROR: &[u8] = b"Internal Server Error";\nstatic NOTFOUND: &[u8] = b"Not Found";\nstatic POST_DATA: &str = r#"{"original": "data"}"#;\nstatic URL: &str = "http://127.0.0.1:1337/json_api";\n\nasync fn client_request_response() -> Result<Response<BoxBody>> {\n    let req = Request::builder()\n        .method(Method::POST)\n        .uri(URL)\n        .header(header::CONTENT_TYPE, "application/json")\n        .body(Full::new(Bytes::from(POST_DATA)))\n        .unwrap();\n\n    let host = req.uri().host().expect("uri has no host");\n    let port = req.uri().port_u16().expect("uri has no port");\n    let stream = TcpStream::connect(format!("{}:{}", host, port)).await?;\n    let io = TokioIo::new(stream);\n\n    let (mut sender, conn) = hyper::client::conn::http1::handshake(io).await?;\n\n    tokio::task::spawn(async move {\n        if let Err(err) = conn.await {\n            println!("Connection error: {:?}", err);\n        }\n    });\n\n    let web_res = sender.send_request(req).await?;\n\n    let res_body = web_res.into_body().boxed();\n\n    Ok(Response::new(res_body))\n}\n\nasync fn api_post_response(req: Request<IncomingBody>) -> Result<Response<BoxBody>> {\n    // Aggregate the body...\n    let whole_body = req.collect().await?.aggregate();\n    // Decode as JSON...\n    let mut data: serde_json::Value = serde_json::from_reader(whole_body.reader())?;\n    // Change the JSON...\n    data["test"] = serde_json::Value::from("test_value");\n    // And respond with the new JSON.\n    let json = serde_json::to_string(&data)?;\n    let response = Response::builder()\n        .status(StatusCode::OK)\n        .header(header::CONTENT_TYPE, "application/json")\n        .body(full(json))?;\n    Ok(response)\n}\n\nasync fn api_get_response() -> Result<Response<BoxBody>> {\n    let data = vec!["foo", "bar"];\n    let res = match serde_json::to_string(&data) {\n        Ok(json) => Response::builder()\n            .header(header::CONTENT_TYPE, "application/json")\n            .body(full(json))\n            .unwrap(),\n        Err(_) => Response::builder()\n            .status(StatusCode::INTERNAL_SERVER_ERROR)\n            .body(full(INTERNAL_SERVER_ERROR))\n            .unwrap(),\n    };\n    Ok(res)\n}\n\nasync fn response_examples(req: Request<IncomingBody>) -> Result<Response<BoxBody>> {\n    match (req.method(), req.uri().path()) {\n        (&Method::GET, "/") | (&Method::GET, "/index.html") => Ok(Response::new(full(INDEX))),\n        (&Method::GET, "/test.html") => client_request_response().await,\n        (&Method::POST, "/json_api") => api_post_response(req).await,\n        (&Method::GET, "/json_api") => api_get_response().await,\n        _ => {\n            // Return 404 not found response.\n            Ok(Response::builder()\n                .status(StatusCode::NOT_FOUND)\n                .body(full(NOTFOUND))\n                .unwrap())\n        }\n    }\n}\n\nfn full<T: Into<Bytes>>(chunk: T) -> BoxBody {\n    Full::new(chunk.into())\n        .map_err(|never| match never {})\n        .boxed()\n}\n\n#[tokio::main]\nasync fn main() -> Result<()> {\n    pretty_env_logger::init();\n\n    let addr: SocketAddr = "127.0.0.1:1337".parse().unwrap();\n\n    let listener = TcpListener::bind(&addr).await?;\n    println!("Listening on http://{}", addr);\n    loop {\n        let (stream, _) = listener.accept().await?;\n        let io = TokioIo::new(stream);\n\n        tokio::task::spawn(async move {\n            let service = service_fn(response_examples);\n\n            if let Err(err) = http1::Builder::new().serve_connection(io, service).await {\n                println!("Failed to serve connection: {:?}", err);\n            }\n        });\n    }\n}\n',
        }
